use std::fs;
use std::path::{Path, PathBuf};

use super::adapter::{BuildAdapter, detect_build_adapter};

/// The static portion of the type declarations for the global `Tako` object.
///
/// The triple-slash reference pulls in `tako.sh`'s ambient globals (the
/// `Tako` global const, `TakoSecrets` placeholder). This file then only
/// contributes project-specific pieces: env var shape and the project's
/// `TakoSecrets` augmentation.
const TAKO_DTS_HEADER: &str = r#"/// <reference types="tako.sh" />
/**
 * AUTO-GENERATED BY TAKO — DO NOT EDIT
 *
 * Regenerated by the Tako CLI on init, dev, deploy, and `tako typegen`.
 * Manual edits will be overwritten on the next run.
 *
 * TypeScript picks these ambient types up only when your project has a
 * `tsconfig.json`. If you don't have one, run `tsc --init` (or
 * `bunx --bun tsc --init`) at the project root — the default `include`
 * glob covers this file.
 */
"#;

// NODE_ENV and runtime-specific vars (BUN_ENV, ...) are declared as own
// properties on the ProcessEnv augmentation — NOT on TakoBaseEnv.
// That's intentional: TakoBaseEnv is also extended by ImportMetaEnv,
// and putting NODE_ENV there would cause a "cannot simultaneously extend"
// collision with Bun.Env / @types/node, which already declare NODE_ENV
// as `string`. As an own property on ProcessEnv it overrides via
// assignability (`RuntimeMode` is assignable to string), so the merge resolves.
const TAKO_DTS_STANDARD_ENVS_PREFIX: &str = r#"
type RuntimeMode = "development" | "production";

interface TakoBaseEnv {
  /** Current environment. */
  readonly ENV?: string;
  /** Port the app should listen on — assigned by the Tako runtime. */
  readonly PORT?: string;
  /** Host/address the app should bind to — assigned by the Tako runtime. */
  readonly HOST?: string;
  /** Build identifier injected by Tako at deploy time. Handy for cache busting and error reporting. */
  readonly TAKO_BUILD?: string;
  /** Per-app persistent data directory provided by Tako. Writes survive restarts. */
  readonly TAKO_DATA_DIR?: string;
}

declare namespace NodeJS {
  interface ProcessEnv extends TakoBaseEnv {
    /** Node runtime alias of ENV. */
    readonly NODE_ENV?: RuntimeMode;
"#;

const TAKO_DTS_STANDARD_ENVS_SUFFIX: &str = r#"  }
}

interface ImportMetaEnv extends TakoBaseEnv {}

interface ImportMeta {
  /** Tako's env surface exposed via `import.meta.env`. */
  readonly env: ImportMetaEnv;
}
"#;

/// Build the full `tako.d.ts` content, including typed secrets.
fn build_dts(secret_names: &[String], adapter: BuildAdapter) -> String {
    let mut out = String::from(TAKO_DTS_HEADER);
    out.push_str(TAKO_DTS_STANDARD_ENVS_PREFIX);
    if matches!(adapter, BuildAdapter::Bun) {
        out.push_str("    /** Bun runtime alias of ENV. */\n");
        out.push_str("    readonly BUN_ENV?: RuntimeMode;\n");
    }
    out.push_str(TAKO_DTS_STANDARD_ENVS_SUFFIX);

    if secret_names.is_empty() {
        out.push_str(
            r#"// eslint-disable-next-line @typescript-eslint/no-empty-object-type
interface TakoSecrets {}
"#,
        );
    } else {
        out.push_str("interface TakoSecrets {\n");
        for name in secret_names {
            out.push_str(&format!(
                "  /** Secret `{}` — injected by Tako at runtime. */\n",
                name
            ));
            out.push_str(&format!("  readonly {}: string;\n", name));
        }
        out.push_str(
            "  /** `String(Tako.secrets)` returns `\"[REDACTED]\"` to prevent accidental leaks. */\n",
        );
        out.push_str("  toString(): \"[REDACTED]\";\n");
        out.push_str(
            "  /** `JSON.stringify(Tako.secrets)` returns `\"[REDACTED]\"` to prevent accidental leaks. */\n",
        );
        out.push_str("  toJSON(): \"[REDACTED]\";\n");
        out.push_str("}\n");
    }

    out
}

/// Write `tako.d.ts` to the project root.
///
/// Returns `true` if the file was written (created or updated),
/// `false` if it already existed with the same content. The JS runtime
/// is autodetected; use [`write_types_for_adapter`] to override.
pub fn write_types(project_dir: &Path) -> std::io::Result<bool> {
    write_types_for_adapter(project_dir, detect_build_adapter(project_dir))
}

/// Like [`write_types`] but with an explicit adapter, so callers that have
/// already resolved the runtime (e.g. `tako typegen`, which honors the
/// `runtime` field in `tako.toml`) don't re-detect.
pub fn write_types_for_adapter(project_dir: &Path, adapter: BuildAdapter) -> std::io::Result<bool> {
    let secret_names = read_secret_names(project_dir);
    write_types_with_secrets(project_dir, &secret_names, adapter)
}

/// Write `tako.d.ts` with explicit secret names.
pub fn write_types_with_secrets(
    project_dir: &Path,
    secret_names: &[String],
    adapter: BuildAdapter,
) -> std::io::Result<bool> {
    let path = resolve_dts_path(project_dir);
    let content = build_dts(secret_names, adapter);
    if path.is_file() {
        let existing = fs::read_to_string(&path)?;
        if existing == content {
            return Ok(false);
        }
    }
    fs::write(&path, content)?;
    Ok(true)
}

/// Resolve where `tako.d.ts` belongs for this project.
///
/// Honors an existing file wherever we find it, so projects with tsconfig
/// `include` patterns like `src/**/*` don't lose their type coverage on
/// regeneration. For fresh projects, prefer `src/` then `app/`, falling
/// back to the project root — that matches the conventions of the TS
/// setups users are most likely to land on (Bun/Node apps, Next.js, Vite).
fn resolve_dts_path(project_dir: &Path) -> PathBuf {
    const CANDIDATE_DIRS: &[&str] = &["src", "app"];

    let root = project_dir.join("tako.d.ts");
    if root.is_file() {
        return root;
    }
    for dir in CANDIDATE_DIRS {
        let candidate = project_dir.join(dir).join("tako.d.ts");
        if candidate.is_file() {
            return candidate;
        }
    }
    for dir in CANDIDATE_DIRS {
        let candidate_dir = project_dir.join(dir);
        if candidate_dir.is_dir() {
            return candidate_dir.join("tako.d.ts");
        }
    }
    root
}

/// Read secret names from `.tako/secrets.json` for the "development" environment.
///
/// Falls back to all secret names across all environments if no development
/// environment exists. Returns an empty vec if the file doesn't exist or is
/// malformed.
fn read_secret_names(project_dir: &Path) -> Vec<String> {
    let secrets_path = project_dir.join(".tako").join("secrets.json");
    let Ok(content) = fs::read_to_string(&secrets_path) else {
        return Vec::new();
    };

    let Ok(parsed): Result<serde_json::Value, _> = serde_json::from_str(&content) else {
        return Vec::new();
    };

    let Some(envs) = parsed.as_object() else {
        return Vec::new();
    };

    // Prefer the development environment's secrets if present
    if let Some(dev) = envs.get("development")
        && let Some(secrets) = dev.get("secrets").and_then(|s| s.as_object())
    {
        let mut names: Vec<String> = secrets.keys().cloned().collect();
        names.sort();
        return names;
    }

    // Fallback: union of secret names across all environments
    let mut names_set = std::collections::BTreeSet::new();
    for env_value in envs.values() {
        if let Some(secrets) = env_value.get("secrets").and_then(|s| s.as_object()) {
            for name in secrets.keys() {
                names_set.insert(name.clone());
            }
        }
    }
    names_set.into_iter().collect()
}

#[cfg(test)]
mod tests {
    use super::*;
    use tempfile::TempDir;

    #[test]
    fn write_types_creates_tako_dts_with_no_secrets() {
        let dir = TempDir::new().unwrap();
        let written = write_types(dir.path()).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("/// <reference types=\"tako.sh\" />"));
        assert!(content.contains("TakoSecrets"));
    }

    #[test]
    fn write_types_is_idempotent() {
        let dir = TempDir::new().unwrap();
        let written_first = write_types(dir.path()).unwrap();
        assert!(written_first);

        let written_second = write_types(dir.path()).unwrap();
        assert!(!written_second);
    }

    #[test]
    fn write_types_with_no_secrets_file_works() {
        let dir = TempDir::new().unwrap();
        let written = write_types(dir.path()).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("/// <reference types=\"tako.sh\" />"));
    }

    #[test]
    fn write_types_with_secrets_generates_typed_interface() {
        let dir = TempDir::new().unwrap();
        let names = vec!["API_KEY".to_string(), "DATABASE_URL".to_string()];
        let written = write_types_with_secrets(dir.path(), &names, BuildAdapter::Bun).unwrap();
        assert!(written);

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("interface TakoSecrets {"));
        assert!(content.contains("readonly API_KEY: string;"));
        assert!(content.contains("readonly DATABASE_URL: string;"));
        assert!(content.contains("toString(): \"[REDACTED]\";"));
        assert!(content.contains("toJSON(): \"[REDACTED]\";"));
    }

    #[test]
    fn write_types_includes_standard_env_typings() {
        let dir = TempDir::new().unwrap();

        write_types_for_adapter(dir.path(), BuildAdapter::Bun).unwrap();

        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("type RuntimeMode = \"development\" | \"production\";"));
        assert!(content.contains("interface TakoBaseEnv"));
        assert!(content.contains("readonly ENV?: string;"));
        assert!(content.contains("readonly PORT?: string;"));
        assert!(content.contains("readonly HOST?: string;"));
        assert!(!content.contains("TAKO_ENV"));
        assert!(content.contains("readonly TAKO_BUILD?: string;"));
        assert!(content.contains("readonly TAKO_DATA_DIR?: string;"));
        assert!(!content.contains("LOG_LEVEL"));
        assert!(!content.contains("TAKO_APP_LOG_LEVEL"));
        assert!(!content.contains("readonly DENO_ENV?:"));
        assert!(content.contains("declare namespace NodeJS"));
        assert!(content.contains("interface ProcessEnv extends TakoBaseEnv {"));
        assert!(content.contains("readonly NODE_ENV?: RuntimeMode;"));
        assert!(content.contains("readonly BUN_ENV?: RuntimeMode;"));
        assert!(content.contains("interface ImportMetaEnv extends TakoBaseEnv {}"));
        assert!(content.contains("/// <reference types=\"tako.sh\" />"));
        assert!(!content.contains("declare const Tako"));
        assert!(!content.contains("interface TakoEnv "));
        let standard_env_block = content
            .split("interface TakoBaseEnv {")
            .nth(1)
            .and_then(|rest| rest.split_once('}'))
            .map(|(body, _)| body)
            .unwrap_or("");
        assert!(!standard_env_block.contains("NODE_ENV"));
        assert!(!standard_env_block.contains("BUN_ENV"));
        assert!(content.contains("interface ImportMeta"));
        assert!(content.contains("readonly env: ImportMetaEnv;"));
    }

    #[test]
    fn write_types_omits_bun_env_for_non_bun_runtimes() {
        for adapter in [
            BuildAdapter::Node,
            BuildAdapter::Deno,
            BuildAdapter::Unknown,
        ] {
            let dir = TempDir::new().unwrap();
            write_types_for_adapter(dir.path(), adapter).unwrap();
            let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
            assert!(
                !content.contains("readonly BUN_ENV"),
                "BUN_ENV should not be declared for adapter {:?}",
                adapter
            );
            assert!(content.contains("readonly NODE_ENV?: RuntimeMode;"));
        }
    }

    #[test]
    fn write_types_reads_secrets_from_development_env() {
        let dir = TempDir::new().unwrap();
        let tako_dir = dir.path().join(".tako");
        fs::create_dir_all(&tako_dir).unwrap();
        fs::write(
            tako_dir.join("secrets.json"),
            r#"{"development":{"secrets":{"DEV_KEY":"encrypted"}}}"#,
        )
        .unwrap();

        write_types(dir.path()).unwrap();
        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("readonly DEV_KEY: string;"));
    }

    #[test]
    fn write_types_prefers_development_over_other_envs() {
        let dir = TempDir::new().unwrap();
        let tako_dir = dir.path().join(".tako");
        fs::create_dir_all(&tako_dir).unwrap();
        fs::write(
            tako_dir.join("secrets.json"),
            r#"{
                "development": {"secrets": {"DEV_KEY": "a"}},
                "production": {"secrets": {"PROD_KEY": "b"}}
            }"#,
        )
        .unwrap();

        write_types(dir.path()).unwrap();
        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("DEV_KEY"));
        assert!(!content.contains("PROD_KEY"));
    }

    #[test]
    fn write_types_honors_existing_file_at_project_root() {
        let dir = TempDir::new().unwrap();
        fs::create_dir_all(dir.path().join("src")).unwrap();
        fs::write(dir.path().join("tako.d.ts"), "// placeholder").unwrap();

        let written = write_types(dir.path()).unwrap();
        assert!(written);

        assert!(!dir.path().join("src").join("tako.d.ts").exists());
        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("/// <reference types=\"tako.sh\" />"));
    }

    #[test]
    fn write_types_honors_existing_file_in_src() {
        let dir = TempDir::new().unwrap();
        fs::create_dir_all(dir.path().join("src")).unwrap();
        fs::write(dir.path().join("src").join("tako.d.ts"), "// old").unwrap();

        let written = write_types(dir.path()).unwrap();
        assert!(written);

        assert!(!dir.path().join("tako.d.ts").exists());
        let content = fs::read_to_string(dir.path().join("src").join("tako.d.ts")).unwrap();
        assert!(content.contains("/// <reference types=\"tako.sh\" />"));
    }

    #[test]
    fn write_types_honors_existing_file_in_app() {
        let dir = TempDir::new().unwrap();
        fs::create_dir_all(dir.path().join("app")).unwrap();
        fs::write(dir.path().join("app").join("tako.d.ts"), "// old").unwrap();

        let written = write_types(dir.path()).unwrap();
        assert!(written);

        assert!(!dir.path().join("tako.d.ts").exists());
        let content = fs::read_to_string(dir.path().join("app").join("tako.d.ts")).unwrap();
        assert!(content.contains("/// <reference types=\"tako.sh\" />"));
    }

    #[test]
    fn write_types_places_in_src_when_src_dir_exists_and_no_file() {
        let dir = TempDir::new().unwrap();
        fs::create_dir_all(dir.path().join("src")).unwrap();

        write_types(dir.path()).unwrap();

        assert!(dir.path().join("src").join("tako.d.ts").is_file());
        assert!(!dir.path().join("tako.d.ts").exists());
    }

    #[test]
    fn write_types_places_in_app_when_only_app_dir_exists() {
        let dir = TempDir::new().unwrap();
        fs::create_dir_all(dir.path().join("app")).unwrap();

        write_types(dir.path()).unwrap();

        assert!(dir.path().join("app").join("tako.d.ts").is_file());
        assert!(!dir.path().join("tako.d.ts").exists());
    }

    #[test]
    fn write_types_prefers_src_over_app_when_both_exist() {
        let dir = TempDir::new().unwrap();
        fs::create_dir_all(dir.path().join("src")).unwrap();
        fs::create_dir_all(dir.path().join("app")).unwrap();

        write_types(dir.path()).unwrap();

        assert!(dir.path().join("src").join("tako.d.ts").is_file());
        assert!(!dir.path().join("app").join("tako.d.ts").exists());
    }

    #[test]
    fn write_types_falls_back_to_root_when_no_src_or_app() {
        let dir = TempDir::new().unwrap();

        write_types(dir.path()).unwrap();

        assert!(dir.path().join("tako.d.ts").is_file());
    }

    #[test]
    fn write_types_falls_back_to_all_envs_when_no_development() {
        let dir = TempDir::new().unwrap();
        let tako_dir = dir.path().join(".tako");
        fs::create_dir_all(&tako_dir).unwrap();
        fs::write(
            tako_dir.join("secrets.json"),
            r#"{"staging":{"secrets":{"STAGE_KEY":"a"}},"production":{"secrets":{"PROD_KEY":"b"}}}"#,
        )
        .unwrap();

        write_types(dir.path()).unwrap();
        let content = fs::read_to_string(dir.path().join("tako.d.ts")).unwrap();
        assert!(content.contains("STAGE_KEY"));
        assert!(content.contains("PROD_KEY"));
    }
}
